import { 神將身, 蔽方, 武拳, 舉臂, 垂臂 } from './shinsho.js';
export const 真達羅 = (bi) => 神將身(bi, {
    臂(bi, 筆) {
        const { M, L, C, Qk, S, 衣, 細 } = 筆;
        // 蔽域：頭光環讓鉤（杆帶＋曲首一體）
        蔽方(bi, [[-15.2, 10.8], [-13.3, 10.8], [-13.3, 2.6], [-9.6, 2.2], [-9.6, -2.7], [-15.2, -2.7]]);
        衣(() => {
            // 杆：雙緣直上
            M(-14.6, 10.7);
            L(-14.6, 1.9);
            S();
            M(-13.9, 10.8);
            L(-13.9, 2.1);
            S();
            // 曲首：內卷如鉤，鋒回垂
            M(-14.6, 1.9);
            C(-14.7, -0.7, -13.4, -2.0, -11.9, -1.7);
            S();
            M(-13.9, 2.1);
            C(-13.95, -0.1, -13.1, -1.15, -12.0, -0.95);
            S();
            M(-11.9, -1.7);
            C(-10.9, -1.45, -10.5, -0.4, -11.0, 0.55);
            S();
            M(-12.0, -0.95);
            Qk(-11.3, -0.75, -11.35, 0.1);
            S();
            M(-11.0, 0.55);
            Qk(-11.15, 0.45, -11.35, 0.1);
            S();
            細(() => { bi.A(-14.25, 2.6, 0.42); }); // 束箍
        });
        // 臂上舉，拳握杆；左垂拳
        const { 拳 } = 舉臂(bi, 筆, -1);
        武拳(bi, 筆, 拳[0], 拳[1]);
        const 左 = 垂臂(bi, 筆, 1);
        武拳(bi, 筆, 左.拳[0], 左.拳[1], { 轉: Math.PI * 0.94, 鏡: -1, 比: 0.96 });
    },
    冠識(bi, 筆) {
        // 寅冠小識：額紋之虎——雙耳・三橫紋
        const { M, L, Qk, S, 細 } = 筆;
        細(() => bi.dim(0.8, () => {
            M(-0.75, 8.2);
            L(-0.55, 7.6);
            S();
            M(-0.55, 7.6);
            L(-0.28, 8.0);
            S();
            M(0.75, 8.2);
            L(0.55, 7.6);
            S();
            M(0.55, 7.6);
            L(0.28, 8.0);
            S();
            M(-0.35, 8.45);
            L(0.35, 8.45);
            S();
            M(-0.3, 8.8);
            L(0.3, 8.8);
            S();
            M(-0.25, 9.15);
            L(0.25, 9.15);
            S();
            M(-0.5, 9.0);
            Qk(0, 9.45, 0.5, 9.0);
            S();
        }));
    },
});
